def calculate_discount(user_role):
    if user_role == 'enterprise':
        return 0.30
    elif user_role == 'premium':
        return 0.15
    else:
        return 0.00

def process_payment(cart_total, discount_percentage):
    discounted_amount = cart_total * discount_percentage
    final_amount = cart_total - discounted_amount
    # Simulate payment processing
    print(f"Processing payment of ${final_amount:.2f} after a {discount_percentage*100}% discount.")
    return final_amount

def process_payment_with_discount(user, cart_items, payment_details):
    user_role = user.role
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    
    if not isinstance(cart_total, (int, float)) or cart_total < 0:
        raise ValueError("Invalid cart total")
    
    discount_percentage = calculate_discount(user_role)
    final_amount = process_payment(cart_total, discount_percentage)
    
    # Simulate payment details processing
    print(f"Payment details: {payment_details}")
    return final_amount

